import re
from beeai.memory import MemoryStore

def detect_tool_injection(memory_store: MemoryStore, session_id: str) -> list[str]:
    entries = memory_store.get_recent_entries(session_id, limit=100)
    dangerous_patterns = [
        r'\b(exec|eval|system|open|__import__)\b',
        r'os\.(system|pop(?:en|en2))',
        r'rm\s+-rf',
        r'base64\.(?:b64decode|decodebytes)'
    ]

    injections = []
    for entry in entries:
        for pattern in dangerous_patterns:
            if re.search(pattern, entry.content, re.IGNORECASE):
                injections.append(entry.id)
    return injections

