from vex_sdk import Vex
from beeai import Agent

# Install: pip install beeai-framework vex-sdk

vex = Vex(api_key="your-vex-key")

@vex.register_detector(
    framework="beeai",
    issue_type="memory_management",
    severity="HIGH"
)
def beeai_memory_issues(agent: Agent, event_data: dict) -> dict:
    if event_data['event_type'] == 'memory_write':
        memory_size = agent.get_memory_store(event_data['session_id']).size_mb()
        if memory_size > 150:
            return {
                'issue': 'UNBOUNDED_MEMORY_GROWTH',
                'severity': 'CRITICAL',
                'fix': 'apply_sliding_window_pruner',
                'metadata': {'size_mb': memory_size}
            }

    elif event_data['event_type'] == 'tool_executed':
        if detect_tool_injection(agent.get_memory_store(event_data['session_id'])):
            return {
                'issue': 'TOOL_INJECTION_DETECTED',
                'severity': 'CRITICAL',
                'fix': 'enable_output_sanitizer'
            }
    return None

# Auto-register with all BeeAI agents
agent.add_event_listener(vex.event_handler)
vex.start_monitoring()
